INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 401, 2, 0.0, 24001, 102301, 10046, "アヤネ", "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 402, 2, 0.0, 24002, 102301, 10046, "アヤネ", "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 2.21);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 403, 2, 0.0, 24003, 102301, 10046, "アヤネ", "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 701, 1, 0.0, 24004, 192201, 10046, "アサヒ", "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 1.99);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 702, 2, 0.0, 24005, 192201, 10046, "アサヒ", "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 2.21);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 703, 1, 0.0, 24006, 192201, 10046, "アサヒ", "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 3.33);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 801, 2, 0.0, 24007, 192301, 10046, "部員３", "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 802, 2, 0.0, 24008, 192301, 10046, "部員３", "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 2.68);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 803, 2, 0.0, 24009, 192301, 10046, "部員３", "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 501, 1, 0.0, 24010, 192501, 10046, "", "やった！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 502, 1, 0.0, 24011, 192501, 10046, "", "勝ったよ！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 503, 1, 0.0, 24012, 192501, 10046, "", "いい調子！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 6, 24, 111, 2, 0.0, 24013, 113501, 10046, "ミサト", "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 5.33);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 112, 2, 0.0, 24014, 113501, 10046, "ミサト", "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 6.85);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 113, 2, 0.0, 24015, 113501, 10046, "ミサト", "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 3.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 611, 2, 0.0, 24016, 192401, 10046, "ダイチ", "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 6.11);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 612, 2, 0.0, 24017, 192401, 10046, "ダイチ", "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 6.75);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 613, 2, 0.0, 24018, 192401, 10046, "ダイチ", "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 211, 1, 0.0, 24019, 113401, 10046, "ハツネ", "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 4.52);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 212, 1, 0.0, 24020, 113401, 10046, "ハツネ", "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 3.89);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 213, 2, 0.0, 24021, 113401, 10046, "ハツネ", "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 13.49);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 311, 2, 0.0, 24022, 106501, 10046, "カヤ", "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 3.17);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 312, 2, 0.0, 24023, 106501, 10046, "カヤ", "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 4.42);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 6, 24, 313, 1, 0.0, 24024, 106501, 10046, "カヤ", "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 2.89);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 4, 24, 421, 3, 0.0, 24025, 102301, 10046, "アヤネ", "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 3.71);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 2, 24, 721, 1, 0.0, 24026, 192201, 10046, "アサヒ", "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 5.1);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 821, 3, 0.0, 24027, 192301, 10046, "部員３", "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 4.34);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 1, 24, 521, 1, 0.0, 24028, 192501, 10046, "", "いい勝負だったよ\nまたやろうね", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", -360.0, 1, 24, 101, 2, 0.0, 24029, 113501, 10046, "ミサト", "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 5.62);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", -360.0, 1, 24, 102, 2, 0.0, 24030, 113501, 10046, "ミサト", "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 9.58);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", -360.0, 2, 24, 103, 2, 0.0, 24031, 113501, 10046, "ミサト", "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", -360.0, 2, 24, 104, 1, 0.0, 24032, 113501, 10046, "ミサト", "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 9.13);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", "2020/07/31 12:00:00", -360.0, 1, 24, 105, 2, 0.0, 24033, 113501, 10046, "ミサト", "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 8.27);
